import java.util.Comparator

fun solve(nums1: Array<Long>, nums0: Array<Long>): Long {
    val n = nums1.size

    // Combine nums1 and nums0 into objects/data structure for sorting
    data class Segment(val ones: Long, val zeros: Long)

    val segments = Array(n) { i ->
        Segment(nums1[i], nums0[i])
    }

    // The core idea is to determine the optimal order. 
    // To maximize the resulting binary number, we want segments that contribute more to the high-order bits to come first.
    // A segment S1 (with ones1, zeros1) should come before S2 (with ones2, zeros2) if 
    // S1 concatenated with S2 (S1S2) results in a larger number than S2 concatenated with S1 (S2S1).
    // Since the length of segments can vary, a direct string comparison is equivalent to comparing the value.
    // S1S2 vs S2S1

    // Let's define a custom comparator for sorting.
    // We compare (S1 + S2) vs (S2 + S1).
    // S1S2 means ones1 '1's followed by zeros1 '0's, followed by ones2 '1's followed by zeros2 '0's.
    // This is complex to compare arithmetically directly across different lengths.

    // A key insight from similar problems (like "Largest Number") is that we define a custom comparison function.
    // For two segments A and B, A comes before B if the binary number represented by AB is greater than the one represented by BA.

    val comparator = Comparator<Segment> { a, b ->
        // Construct the binary representation for AB and BA.
        // AB: (onesA ones) (zerosA zeros) (onesB ones) (zerosB zeros)
        // BA: (onesB ones) (zerosB zeros) (onesA ones) (zerosA zeros)

        // Instead of building strings (which can be too slow/large for comparison), 
        // we compare them based on how many high-order bits are set.

        // Consider the structure: 1...1 0...0.
        // The value is roughly (2^ones - 1) * 2^zeros + (2^ones2 - 1).

        // A simpler comparison strategy often works for these concatenation problems: 
        // Compare the value of (A concatenated with B) vs (B concatenated with A).

        // Since we are dealing with large numbers modulo 10^9 + 7, direct arithmetic comparison is hard 
        // because we need the *actual* maximum value first, then modulo. 
        // However, the sorting order itself must be determined by the lexicographically largest sequence, 
        // which corresponds to the largest integer value.

        // Let's use string concatenation for comparison, as N is up to 10^5 and total length up to 2*10^5.
        // String operations might pass given the constraints on total length.

        val sA = "1".repeat(a.ones.toInt()).padEnd(a.ones.toInt(), '0') + "0".repeat(a.zeros.toInt())
        val sB = "1".repeat(b.ones.toInt()).padEnd(b.ones.toInt(), '0') + "0".repeat(b.zeros.toInt())

        // Reconstructing the segment string accurately:
        val strA = "1".repeat(a.ones.toInt()) + "0".repeat(a.zeros.toInt())
        val strB = "1".repeat(b.ones.toInt()) + "0".repeat(b.zeros.toInt())

        val strAB = strA + strB
        val strBA = strB + strA

        // Compare lexicographically: greater means it should come first (descending order)
        strAB.compareTo(strBA)
    }

    segments.sortWith(comparator)

    // Concatenate the sorted segments
    var resultString = ""
    for (segment in segments) {
        val segmentStr = "1".repeat(segment.ones.toInt()) + "0".repeat(segment.zeros.toInt())
        resultString += segmentStr
    }

    // Calculate the resulting integer value modulo 10^9 + 7
    val MOD: Long = 1_000_000_007L
    var maxValue: Long = 0
    var powerOf2: Long = 1 // Represents 2^k mod MOD, starting with 2^0 = 1

    // Iterate through the final string from right to left (LSB to MSB)
    for (i in resultString.length - 1 downTo 0) {
        val bit = if (resultString[i] == '1') 1L else 0L

        // Contribution of this bit: bit * 2^(position) mod MOD
        val contribution = (bit * powerOf2) % MOD

        maxValue = (maxValue + contribution) % MOD

        // Update powerOf2 for the next position (2^(k+1))
        powerOf2 = (powerOf2 * 2) % MOD
    }

    return maxValue
}
