        // is at position `currentOffset + ones - 1` from the left.
        // Its weight in the total number is 2^(L_total - 1 - (currentOffset + ones - 1))
        // = 2^(L_total - currentOffset - ones)

        // The 'zeros' part:
        // They are trailing zeros, contributing 0 to the value.

        // The value contributed by the 'ones' is:
        // Sum_{k=0}^{ones-1} 2^(L_total - 1 - (currentOffset + k))

        // This is a geometric series: 2^p + 2^(p-1) + ... + 2^(p-ones+1)
        // where p = L_total - 1 - currentOffset.

        if (ones > 0) {
            // The highest power of 2 for the leftmost '1' is at index:
            // L_total - 1 - (currentOffset + 0) = L_total - currentOffset - 1
            val highPowerExponent = (L_total - currentOffset - 1).toInt()

            // The lowest power of 2 for the rightmost '1' is at index:
            // L_total - 1 - (currentOffset + ones - 1) = L_total - currentOffset - ones
            val lowPowerExponent = (L_total - currentOffset - ones).toInt()

            // Sum = 2^(highPowerExponent + 1) - 2^(lowPowerExponent)
            // Since we are working modulo MOD, we need modular exponentiation.

            // Contribution = (2^(highPowerExponent + 1) - 2^lowPowerExponent) mod MOD

            val term1 = power(2, highPowerExponent + 1, mod)
            val term2 = power(2, lowPowerExponent, mod)

            var contribution = (term1 - term2 + mod) % mod

            result = (result + contribution) % mod
        }

        // Update offset
        currentOffset += length
    }

    return result
}

/**
 * Modular exponentiation: (base^exp) % mod
 */
private fun power(base: Long, exp: Int, mod: Long): Long {
    var res: Long = 1
    var b: Long = base % mod
    var e: Int = exp
    while (e > 0) {
        if (e % 2 == 1) {
            res = (res * b) % mod
        }
        b = (b * b) % mod
        e /= 2
    }
    return res
}
